document.addEventListener("DOMContentLoaded",(()=>{const e=document.getElementById("popover-btn"),t=document.getElementById("popover");if(!e||!t)return void console.error("Кнопка или попвер не найдены в DOM!");const n=e.dataset.popoverTitle||"Заголовок по умолчанию",o=e.dataset.content||"Текст контента по умолчанию";t.innerHTML=`\n    <div class="popover-title">${n}</div>\n    <div class="popover-content">${o}</div>\n  `,e.addEventListener("click",(e=>{e.stopPropagation();const n="block"===t.style.display;t.style.display=n?"none":"block",console.log("Попвер переключён:",n?"скрыт":"показан")})),document.addEventListener("click",(n=>{t.contains(n.target)||n.target===e||(t.style.display="none")})),document.addEventListener("keydown",(e=>{"Escape"===e.key&&(t.style.display="none")}))})),window.togglePopover=function(e=null){const t=document.getElementById("popover");t&&(t.style.display=null===e?"block"===t.style.display?"none":"block":e?"block":"none")},window.updatePopoverContent=function(e,t){const n=document.getElementById("popover"),o=document.getElementById("popover-btn");if(n&&o){e&&(o.dataset.popoverTitle=e),t&&(o.dataset.content=t);const d=e||o.dataset.popoverTitle||"Заголовок по умолчанию",l=t||o.dataset.content||"Текст контента по умолчанию";n.innerHTML=`\n      <div class="popover-title">${d}</div>\n      <div class="popover-content">${l}</div>\n    `}};